 Capítulo 6 Modelado predictivo Se implementó un pipeline reproducible que integra preprocesamiento y clasificación, evaluando cinco algoritmos con énfasis en el Recall como métrica principal. 6.1 Preparación de datos X &lt;- df[, names(df) != &quot;HeartDiseaseorAttack&quot;] y &lt;- df[[&quot;HeartDiseaseorAttack&quot;]] set.seed(42) idx_train &lt;- createDataPartition(y, p = 0.8, list = FALSE) X_train &lt;- X[idx_train, ]; X_test &lt;- X[-idx_train, ] y_train &lt;- y[idx_train]; y_test &lt;- y[-idx_train] cat(&quot;Entrenamiento:&quot;, nrow(X_train), &quot;registros
&quot;) ## Entrenamiento: 202944 registros cat(&quot;Test: &quot;, nrow(X_test), &quot;registros
&quot;) ## Test: 50736 registros negativos &lt;- sum(y_train == 0) positivos &lt;- sum(y_train == 1) scale_pos &lt;- negativos / positivos cat(sprintf(&quot;scale_pos_weight: %.2f
&quot;, scale_pos)) ## scale_pos_weight: 9.66 # Escalar variables continuas con MinMax continuous_vars &lt;- c(&quot;BMI&quot;,&quot;MentHlth&quot;,&quot;PhysHlth&quot;) preproc &lt;- preProcess(X_train[, continuous_vars], method = &quot;range&quot;) X_train[, continuous_vars] &lt;- predict(preproc, X_train[, continuous_vars]) X_test[, continuous_vars] &lt;- predict(preproc, X_test[, continuous_vars]) X_train_mat &lt;- as.matrix(X_train) X_test_mat &lt;- as.matrix(X_test) 6.2 Entrenamiento de modelos 6.2.1 Regresión Logística lr_weights &lt;- ifelse(y_train == 1, negativos / positivos, 1) lr_model &lt;- glm(y ~ ., data = data.frame(X_train, y = y_train), family = binomial, weights = lr_weights) lr_proba &lt;- predict(lr_model, newdata = as.data.frame(X_test), type = &quot;response&quot;) lr_pred &lt;- as.integer(lr_proba &gt;= 0.5) cat(&quot;LR — Recall:&quot;, round(Recall(y_test, lr_pred, positive = &quot;1&quot;), 4), &quot;| AUC:&quot;, round(auc(roc(y_test, lr_proba, quiet = TRUE)), 4), &quot;
&quot;) ## LR — Recall: 0.7973 | AUC: 0.846 6.2.2 Random Forest set.seed(42) rf_model &lt;- randomForest(x = X_train_mat, y = factor(y_train), ntree = 100, classwt = c(&quot;0&quot;=1, &quot;1&quot;=scale_pos)) rf_proba &lt;- predict(rf_model, X_test_mat, type = &quot;prob&quot;)[, &quot;1&quot;] rf_pred &lt;- as.integer(as.character(predict(rf_model, X_test_mat))) cat(&quot;RF — Recall:&quot;, round(Recall(y_test, rf_pred, positive = &quot;1&quot;), 4), &quot;| AUC:&quot;, round(auc(roc(y_test, rf_proba, quiet = TRUE)), 4), &quot;
&quot;) ## RF — Recall: 0.4352 | AUC: 0.7677 6.2.3 XGBoost dtrain &lt;- xgb.DMatrix(data = X_train_mat, label = y_train) dtest &lt;- xgb.DMatrix(data = X_test_mat, label = y_test) params &lt;- list(objective = &quot;binary:logistic&quot;, eval_metric = &quot;logloss&quot;, learning_rate = 0.05, max_depth = 3, subsample = 0.8, scale_pos_weight = scale_pos, verbosity = 0) set.seed(42) xgb_model &lt;- xgb.train(params = params, data = dtrain, nrounds = 100, verbose = 0) xgb_proba &lt;- predict(xgb_model, dtest) xgb_pred &lt;- as.integer(xgb_proba &gt;= 0.5) cat(&quot;XGB — Recall:&quot;, round(Recall(y_test, xgb_pred, positive = &quot;1&quot;), 4), &quot;| AUC:&quot;, round(auc(roc(y_test, xgb_proba, quiet = TRUE)), 4), &quot;
&quot;) ## XGB — Recall: 0.822 | AUC: 0.8477 6.3 Tabla comparativa Table 6.1: Table 6.2: Comparación de modelos en el conjunto de test Modelo Accuracy Precision Recall F1 AUC-ROC Regresión Logística 0.7525 0.2506 0.7973 0.3814 0.846 Random Forest 0.8047 0.2277 0.4352 0.299 0.7677 XGBoost 0.7321 0.2387 0.822 0.37 0.8477 XGBoost lidera en Recall y AUC-ROC, siendo seleccionado como modelo ganador. 6.4 Curvas ROC comparativas roc_lr &lt;- roc(y_test, lr_proba, quiet = TRUE) roc_rf &lt;- roc(y_test, rf_proba, quiet = TRUE) roc_xgb &lt;- roc(y_test, xgb_proba, quiet = TRUE) ggroc(list( &quot;LogReg&quot; = roc_lr, &quot;RandomForest&quot; = roc_rf, &quot;XGBoost&quot; = roc_xgb )) + scale_color_manual(values = c(riesgo_color, nude_palette[2], &quot;#4A7C59&quot;), labels = c( paste0(&quot;LogReg (AUC=&quot;, round(auc(roc_lr), 3), &quot;)&quot;), paste0(&quot;RandomForest (AUC=&quot;, round(auc(roc_rf), 3), &quot;)&quot;), paste0(&quot;XGBoost (AUC=&quot;, round(auc(roc_xgb), 3), &quot;)&quot;) )) + geom_abline(slope = 1, intercept = 1, linetype = &quot;dashed&quot;, color = &quot;gray&quot;) + labs(title = &quot;Curvas ROC — Comparación de modelos&quot;, x = &quot;Especificidad&quot;, y = &quot;Sensibilidad (Recall)&quot;, color = &quot;Modelo&quot;) + theme(legend.position = &quot;bottom&quot;) Figure 6.1: Comparación de curvas ROC 6.5 Threshold tuning — XGBoost thresholds &lt;- seq(0.1, 0.9, length.out = 100) recalls_t &lt;- sapply(thresholds, function(t) Recall(y_test, as.integer(xgb_proba&gt;=t), positive=&quot;1&quot;)) precisions_t &lt;- sapply(thresholds, function(t) Precision(y_test, as.integer(xgb_proba&gt;=t), positive=&quot;1&quot;)) f1s_t &lt;- sapply(thresholds, function(t) F1_Score(y_test, as.integer(xgb_proba&gt;=t), positive=&quot;1&quot;)) best_t &lt;- thresholds[which.max(f1s_t)] cat(sprintf(&quot;Umbral óptimo (mejor F1): %.2f
&quot;, best_t)) ## Umbral óptimo (mejor F1): 0.69 data.frame( Umbral = rep(thresholds, 3), Valor = c(recalls_t, precisions_t, f1s_t), Metrica = rep(c(&quot;Recall&quot;,&quot;Precision&quot;,&quot;F1&quot;), each = length(thresholds)) ) |&gt; ggplot(aes(x = Umbral, y = Valor, color = Metrica)) + geom_line(linewidth = 1.2) + geom_vline(xintercept = best_t, linetype = &quot;dashed&quot;, color = &quot;gray40&quot;) + annotate(&quot;text&quot;, x = best_t + 0.01, y = 0.08, label = paste0(&quot;Umbral óptimo F1: &quot;, round(best_t,2)), hjust = 0, size = 3.5) + scale_color_manual(values = c(&quot;Recall&quot;=riesgo_color, &quot;Precision&quot;=nude_palette[2], &quot;F1&quot;=&quot;#4A7C59&quot;)) + labs(title = paste(&quot;Threshold tuning — XGBoost&quot;), x = &quot;Umbral de decisión&quot;, y = &quot;Métrica&quot;) + theme(legend.position = &quot;bottom&quot;) Figure 6.2: Trade-off Recall / Precision según umbral de decisión Decisión: Se mantiene el umbral por defecto (0.50) para priorizar el Recall (0.82), dado que en un contexto médico preventivo el costo de no detectar un caso positivo supera el de generar un falso positivo. 6.6 Importancia de variables — XGBoost imp &lt;- xgb.importance(feature_names = colnames(X_train_mat), model = xgb_model) imp_ord &lt;- imp[order(imp$Gain), ] ggplot(imp_ord, aes(x = Gain, y = reorder(Feature, Gain))) + geom_col(fill = riesgo_color, color = &quot;white&quot;, width = 0.65) + geom_text(aes(label = round(Gain, 4)), hjust = -0.1, size = 3) + labs(title = &quot;Importancia de variables — XGBoost&quot;, x = &quot;Importancia (Gain)&quot;, y = NULL) + theme(legend.position = &quot;none&quot;) Figure 6.3: Importancia de variables según XGBoost (Gain) 6.7 Modelo final: XGBoost con 12 variables Cinco variables presentaron importancia cero y cuatro más fueron marginales. Se construyó un modelo reducido con las 12 variables de mayor importancia, obteniendo resultados prácticamente idénticos. top_vars &lt;- c(&quot;HighBP&quot;,&quot;GenHlth&quot;,&quot;HighChol&quot;,&quot;Age&quot;,&quot;DiffWalk&quot;, &quot;Sex&quot;,&quot;Stroke&quot;,&quot;Smoker&quot;,&quot;Diabetes&quot;,&quot;PhysHlth&quot;, &quot;Income&quot;,&quot;HvyAlcoholConsump&quot;) X_final &lt;- df[, top_vars] set.seed(42) idx_f &lt;- createDataPartition(y, p = 0.8, list = FALSE) X_tr_f &lt;- X_final[idx_f, ]; X_te_f &lt;- X_final[-idx_f, ] y_tr_f &lt;- y[idx_f]; y_te_f &lt;- y[-idx_f] # Escalar PhysHlth pre_f &lt;- preProcess(X_tr_f[,&quot;PhysHlth&quot;,drop=FALSE], method=&quot;range&quot;) X_tr_f$PhysHlth &lt;- predict(pre_f, X_tr_f[,&quot;PhysHlth&quot;,drop=FALSE])[,1] X_te_f$PhysHlth &lt;- predict(pre_f, X_te_f[,&quot;PhysHlth&quot;,drop=FALSE])[,1] scale_f &lt;- sum(y_tr_f==0)/sum(y_tr_f==1) dtrain_f &lt;- xgb.DMatrix(data=as.matrix(X_tr_f), label=y_tr_f) dtest_f &lt;- xgb.DMatrix(data=as.matrix(X_te_f), label=y_te_f) params_f &lt;- list(objective=&quot;binary:logistic&quot;, eval_metric=&quot;logloss&quot;, learning_rate=0.05, max_depth=3, subsample=1.0, scale_pos_weight=scale_f, verbosity=0) set.seed(42) modelo_f &lt;- xgb.train(params=params_f, data=dtrain_f, nrounds=100, verbose=0) y_pred_f &lt;- as.integer(predict(modelo_f, dtest_f) &gt;= 0.5) y_proba_f &lt;- predict(modelo_f, dtest_f) Table 6.3: Table 6.4: Métricas del modelo final — XGBoost (12 variables) Métrica Valor Accuracy 0.7338 Precision 0.2398 Recall 0.8210 F1 0.3712 AUC-ROC 0.8477 cm_f &lt;- table(Predicho = y_pred_f, Real = y_te_f) cm_long &lt;- as.data.frame(cm_f) names(cm_long) &lt;- c(&quot;Predicho&quot;,&quot;Real&quot;,&quot;Freq&quot;) cm_long$Predicho &lt;- factor(cm_long$Predicho, levels=c(1,0), labels=c(&quot;Con HD&quot;,&quot;Sin HD&quot;)) cm_long$Real &lt;- factor(cm_long$Real, levels=c(0,1), labels=c(&quot;Sin HD&quot;,&quot;Con HD&quot;)) ggplot(cm_long, aes(x=Real, y=Predicho, fill=Freq)) + geom_tile() + geom_text(aes(label=format(Freq, big.mark=&quot;,&quot;)), size=6, color=&quot;white&quot;, fontface=&quot;bold&quot;) + scale_fill_gradient(low=&quot;#f0f0f0&quot;, high=riesgo_color) + labs(title=&quot;Matriz de confusión — XGBoost (12 variables)&quot;, x=&quot;Clase real&quot;, y=&quot;Clase predicha&quot;) + theme(legend.position=&quot;none&quot;) Figure 6.4: Matriz de confusión — Modelo final roc_f &lt;- roc(y_te_f, y_proba_f, quiet=TRUE) ggroc(roc_f, color=riesgo_color, size=1.2) + geom_abline(slope=1, intercept=1, linetype=&quot;dashed&quot;, color=&quot;gray&quot;) + annotate(&quot;text&quot;, x=0.3, y=0.15, label=paste0(&quot;AUC = &quot;, round(auc(roc_f), 4)), size=5, color=riesgo_color) + labs(title=&quot;Curva ROC — XGBoost (12 variables)&quot;, x=&quot;Especificidad&quot;, y=&quot;Sensibilidad (Recall)&quot;) Figure 6.5: Curva ROC — Modelo final Conclusión: Con solo 12 preguntas de encuesta telefónica, el modelo detecta más de 8 de cada 10 personas con enfermedad cardíaca, sin necesidad de exámenes de laboratorio ni procedimientos costosos.
